/* Full list (ремонт различных брендов) */

let containers = document.querySelectorAll('.container')
let brandContainer = containers[0]
let buttonFullBrand = brandContainer.querySelector('.more-button')
let brandBlock = brandContainer.querySelector('.brand-block')
let brandButtonText = buttonFullBrand.querySelector('.button-text')
let defaultBrandText = brandButtonText.textContent
let buttonTextContent = 'Показать все'

buttonFullBrand.addEventListener('click', function () {
  brandBlock.classList.toggle('brand-block_full-list')
  buttonFullBrand.classList.toggle('more-button_open')

  if (brandBlock.classList.contains('brand-block_full-list') === true) {
    brandButtonText.textContent = 'Скрыть'
  } else {
    brandButtonText.textContent = buttonTextContent
  }
})

