/* openClose Aside-menu */

let asideMenu = document.querySelector('.aside-menu')
let body = document.querySelector('.body')
let menuButton = document.querySelector('.burger-button')
let closeButton = document.querySelector('.top__close-button')
let screenCloseButton = document.querySelector('.screenClick-close')
let asideMenuClassAdd = 'aside-menu_active'

let openClose = function (asideButton, menu, classAdd) {
  asideButton.onclick = function () {
    menu.classList.toggle(classAdd)
    body.classList.toggle('overflow-hidden')
  }
}

openClose(menuButton, asideMenu, asideMenuClassAdd)
openClose(closeButton, asideMenu, asideMenuClassAdd)
openClose(screenCloseButton, asideMenu, asideMenuClassAdd)

